  readonly manifest: SpriteManifest;
  readonly sourceArtifactPath: string;
};

export type ArtDirectorRejectedSprite = {
  readonly entityId: string;
  readonly fallbackSpriteId: FallbackSpriteId;
  readonly reason: string;
  readonly sourceArtifactPath: string | null;
};

export type ArtDirectorBatchResult = {
  readonly accepted: readonly ArtDirectorAcceptedSprite[];
  readonly rejected: readonly ArtDirectorRejectedSprite[];
};

/**
 * Seam only. A future provider writes sprite-manifest v1 data, the Art Gauntlet
 * validates/rasterizes it, and accepted manifests enter the atlas under
 * (themeId, entityId, seed). Rejections continue through fallback sprites.
 */
export interface ArtDirector {
  generateSprites(
    request: ArtDirectorBatchRequest,
    options?: { readonly signal?: AbortSignal }
  ): Promise<ArtDirectorBatchResult>;
}

export const SPRITE_MANIFEST_VERSION = "everdeep.sprite-manifest.v1";

export const ALLOWED_SPRITE_SIZES = [16, 24] as const;
export const MAX_PALETTE_COLORS = 15;
export const MIN_FILLED_RATIO = 0.08;

export type SpriteSize = (typeof ALLOWED_SPRITE_SIZES)[number];
export type HexColor = `#${string}`;

export type SpriteManifest = {
  readonly w: SpriteSize;
  readonly h: SpriteSize;
  readonly palette: readonly HexColor[];
  readonly px: readonly (readonly number[])[];
};

export type SpriteValidationError = {
  readonly path: string;
  readonly message: string;
};

export type SpriteValidationResult =
  | {
      readonly ok: true;
      readonly manifest: SpriteManifest;
    }
  | {
      readonly ok: false;
      readonly errors: readonly SpriteValidationError[];
    };

export type RasterizedSprite = {
  readonly width: number;
  readonly height: number;
  readonly scale: number;
  readonly pixels: Uint8ClampedArray;
};

export type SpriteManifestStats = {
  readonly totalPixels: number;
  readonly filledPixels: number;
  readonly filledRatio: number;
  readonly visibleColorCount: number;
  readonly occupiedRows: number;
  readonly occupiedColumns: number;
};

const HEX_RGB = /^#[0-9a-f]{6}$/;

export const parseSpriteManifestJson = (
  text: string
): SpriteValidationResult => {
  let value: unknown;

  try {
    value = JSON.parse(text);
  } catch (error) {
    return {
      ok: false,
      errors: [
        {
          path: "<json>",
          message: error instanceof Error ? error.message : String(error)
        }
      ]
    };
  }

  return validateSpriteManifest(value);
};

export const validateSpriteManifest = (
  value: unknown
): SpriteValidationResult => {
  const errors: SpriteValidationError[] = [];

  if (!isPlainObject(value)) {
    return {
      ok: false,
      errors: [{ path: "<root>", message: "manifest must be an object" }]
    };
  }

  const allowedKeys = new Set(["w", "h", "palette", "px"]);
  for (const key of Object.keys(value)) {
    if (!allowedKeys.has(key)) {
      errors.push({
        path: key,
        message: "unknown field; v1 sprite manifests are strict"
      });
    }
  }

  const w = value.w;
  const h = value.h;
  const palette = value.palette;
  const px = value.px;

  if (!Number.isInteger(w) || !isAllowedSize(w)) {
    errors.push({
      path: "w",
      message: `w must be one of ${ALLOWED_SPRITE_SIZES.join(", ")}`
    });
  }

  if (!Number.isInteger(h) || !isAllowedSize(h)) {
    errors.push({
      path: "h",
      message: `h must be one of ${ALLOWED_SPRITE_SIZES.join(", ")}`
    });
  }

  if (Number.isInteger(w) && Number.isInteger(h) && w !== h) {
    errors.push({ path: "h", message: "w and h must match" });
  }

  if (!Array.isArray(palette)) {
    errors.push({ path: "palette", message: "palette must be an array" });
  } else {
    if (palette.length < 1 || palette.length > MAX_PALETTE_COLORS) {
      errors.push({
        path: "palette",
        message: `palette must contain 1-${MAX_PALETTE_COLORS} colors`
      });
    }

    const seenColors = new Set<string>();
    palette.forEach((color, index) => {
      if (typeof color !== "string" || !HEX_RGB.test(color)) {
        errors.push({
          path: `palette[${index}]`,
          message: "palette colors must be lowercase #rrggbb strings"
        });
        return;
      }

      if (seenColors.has(color)) {
        errors.push({
          path: `palette[${index}]`,
          message: "duplicate palette color"
        });
      }

      seenColors.add(color);
    });
  }

  const width = isAllowedSize(w) ? w : null;
  const height = isAllowedSize(h) ? h : null;
  const maxIndex = Array.isArray(palette) ? palette.length : 0;

  if (!Array.isArray(px)) {
    errors.push({ path: "px", message: "px must be a row-major matrix" });
  } else {
    if (height !== null && px.length !== height) {
      errors.push({
        path: "px",
        message: `px must contain exactly ${height} rows`
      });
    }

    px.forEach((row, y) => {
      if (!Array.isArray(row)) {
        errors.push({ path: `px[${y}]`, message: "row must be an array" });
        return;
      }

      if (width !== null && row.length !== width) {
        errors.push({
          path: `px[${y}]`,
          message: `row must contain exactly ${width} columns`
        });
      }

      row.forEach((cell, x) => {
        if (!Number.isInteger(cell)) {
          errors.push({
            path: `px[${y}][${x}]`,
            message: "palette index must be an integer"
          });
          return;
        }

        if (cell < 0 || cell > maxIndex) {
          errors.push({
            path: `px[${y}][${x}]`,
            message: `palette index must be between 0 and ${maxIndex}`
          });
        }
      });
    });
  }

  if (width !== null && height !== null && Array.isArray(px)) {
    const stats = spriteManifestStatsForShape(width, height, px);

    if (stats.filledPixels === 0) {
      errors.push({
        path: "px",
        message: "sprite must contain at least one non-transparent pixel"
      });
    } else if (stats.filledRatio < MIN_FILLED_RATIO) {
      errors.push({
        path: "px",
        message: `sprite must fill at least ${Math.round(
          MIN_FILLED_RATIO * 100
        )}% of pixels`
      });
    }

    if (stats.filledPixels > 0 && stats.occupiedRows < 3) {
      errors.push({
        path: "px",
        message: "non-transparent pixels must occupy at least 3 rows"
      });
    }

    if (stats.filledPixels > 0 && stats.occupiedColumns < 3) {
      errors.push({
        path: "px",
        message: "non-transparent pixels must occupy at least 3 columns"
      });
    }

    if (stats.filledPixels > 0 && stats.visibleColorCount < 2) {
      errors.push({
        path: "px",
        message: "sprite must use at least 2 visible palette colors"
      });
    }
  }

  if (errors.length > 0) {
    return { ok: false, errors };
  }

  return { ok: true, manifest: value as SpriteManifest };
};

export const formatSpriteValidationErrors = (
  errors: readonly SpriteValidationError[]
): string =>
  errors.map((error) => `${error.path}: ${error.message}`).join("; ");

export const spriteManifestStats = (
  manifest: SpriteManifest
): SpriteManifestStats =>
  spriteManifestStatsForShape(manifest.w, manifest.h, manifest.px);

export const rasterizeSpriteManifest = (
  manifest: SpriteManifest,
  options: { readonly scale?: number } = {}
): RasterizedSprite => {
  const scale = options.scale ?? 1;

  if (!Number.isInteger(scale) || scale < 1 || scale > 32) {
    throw new Error("scale must be an integer from 1 to 32");
  }

  const validated = validateSpriteManifest(manifest);
  if (!validated.ok) {
    throw new Error(
      `invalid sprite manifest: ${formatSpriteValidationErrors(
        validated.errors
      )}`
    );
  }

  const width = manifest.w * scale;
  const height = manifest.h * scale;
  const pixels = new Uint8ClampedArray(width * height * 4);
  const colors = manifest.palette.map(parseHexRgb);

  for (let sourceY = 0; sourceY < manifest.h; sourceY += 1) {
    const row = manifest.px[sourceY];
    if (row === undefined) {
      throw new Error(`missing sprite row ${sourceY}`);
    }

    for (let sourceX = 0; sourceX < manifest.w; sourceX += 1) {
      const paletteIndex = row[sourceX] ?? 0;
      if (paletteIndex === 0) {
        continue;
      }

      const color = colors[paletteIndex - 1];
      if (color === undefined) {
        throw new Error(`missing palette color ${paletteIndex}`);
      }

      for (let offsetY = 0; offsetY < scale; offsetY += 1) {
        for (let offsetX = 0; offsetX < scale; offsetX += 1) {
          const targetX = sourceX * scale + offsetX;
          const targetY = sourceY * scale + offsetY;
          const targetOffset = (targetY * width + targetX) * 4;
          pixels[targetOffset] = color.red;
          pixels[targetOffset + 1] = color.green;
          pixels[targetOffset + 2] = color.blue;
          pixels[targetOffset + 3] = 255;
        }
      }
    }
  }

  return { width, height, scale, pixels };
};

const isAllowedSize = (value: unknown): value is SpriteSize =>
  value === 16 || value === 24;

const isPlainObject = (
  value: unknown
): value is { readonly [key: string]: unknown } =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const spriteManifestStatsForShape = (
  width: number,
  height: number,
  px: readonly unknown[]
): SpriteManifestStats => {
  let filledPixels = 0;
  const visibleColors = new Set<number>();
  const occupiedRows = new Set<number>();
  const occupiedColumns = new Set<number>();

  px.forEach((row, y) => {
    if (!Array.isArray(row)) {
      return;
    }

    row.forEach((cell, x) => {
      if (Number.isInteger(cell) && cell > 0) {
        filledPixels += 1;
        visibleColors.add(cell);
        occupiedRows.add(y);
        occupiedColumns.add(x);
      }
    });
  });

  const totalPixels = width * height;

  return {
    totalPixels,
    filledPixels,
    filledRatio: filledPixels / totalPixels,
    visibleColorCount: visibleColors.size,
    occupiedRows: occupiedRows.size,
    occupiedColumns: occupiedColumns.size
  };
};

const parseHexRgb = (
  hex: HexColor
): { readonly red: number; readonly green: number; readonly blue: number } => ({
  red: Number.parseInt(hex.slice(1, 3), 16),
  green: Number.parseInt(hex.slice(3, 5), 16),

import { Terrain, type TerrainKind } from "../engine/map/index.js";
import { isTrapRevealed } from "../engine/render/index.js";
import type {
  EntityId,
  EntityInstance,
  GameState,
  Position,
  SerializableRecord,
  TrapEntityInstance
} from "../engine/state/index.js";
import type { BehaviorKind, ItemCategory } from "../schemas/entities/index.js";
import {
  FALLBACK_THEME_ID,
  spriteAtlasKey,
  type SpriteAtlasKey,
  type SpriteAtlasThemeId
} from "./atlas.js";
import type { FallbackSpriteId } from "./fallback.js";

export type ArtResolverLayer =
  | "player"
  | "enemy"
  | "npc"
  | "item"
  | "trap"
  | "terrain"
  | "empty";

export type ArtResolverCellView = {
  readonly x: number;
  readonly y: number;
  readonly terrain: string;
  readonly layer: ArtResolverLayer;
  readonly featureKind: string;
  readonly featureId: string;
};

export type ArtResolverOptions = {
  readonly themeId?: SpriteAtlasThemeId;
  readonly seed?: string;
  readonly revealHiddenTraps?: boolean;
};

export type ResolvedSprite = {
  readonly spriteId: FallbackSpriteId;
  readonly atlasKey: SpriteAtlasKey;
  readonly reason: string;
};

export const TERRAIN_SPRITE_MAP = {
  [Terrain.Floor]: "terrain.floor",
  [Terrain.Wall]: "terrain.wall",
  [Terrain.Door]: "terrain.door",
  [Terrain.Water]: "terrain.water",
  [Terrain.StairsDown]: "terrain.stairs_down",
  [Terrain.Entrance]: "terrain.entrance"
} as const satisfies Record<TerrainKind, FallbackSpriteId>;

export const ITEM_KIND_SPRITE_MAP = {
  weapon: "item.gear",
  armor: "item.gear",
  charm: "item.gear",
  draught: "item.consumable",
  note: "item.consumable",
  throwable: "item.consumable",
  food: "item.consumable",
  tool: "item.consumable",
  key_item: "item.treasure",
  coin: "item.treasure"
} as const satisfies Record<ItemCategory, FallbackSpriteId>;

export const ENEMY_BEHAVIOR_SPRITE_MAP = {
  approach_melee: "enemy.brute",
  keep_range: "enemy.skirmisher",
  flee_low_hp: "enemy.skirmisher",
  pack_hunter: "enemy.brute",
  ambusher: "enemy.skirmisher",
  territorial: "enemy.brute",
  guard: "enemy.brute",
  patrol: "enemy.skirmisher",
  thief: "enemy.skirmisher",
  caster: "enemy.caster",
  bodyguard: "enemy.brute",
  mimic: "enemy.caster"
} as const satisfies Record<BehaviorKind, FallbackSpriteId>;

export const TRAP_STATE_SPRITE_MAP = {
  hidden: "trap.hidden",
  revealed: "trap.revealed"
} as const satisfies Record<"hidden" | "revealed", FallbackSpriteId>;

export const RESOLVER_MAPPING_TABLE = [
  ...Object.entries(TERRAIN_SPRITE_MAP).map(([discriminant, spriteId]) => ({
    discriminant: `terrain.${discriminant}`,
    spriteId
  })),
  ...Object.entries(ITEM_KIND_SPRITE_MAP).map(([discriminant, spriteId]) => ({
    discriminant: `item.${discriminant}`,
    spriteId
  })),
  ...Object.entries(ENEMY_BEHAVIOR_SPRITE_MAP).map(
    ([discriminant, spriteId]) => ({
      discriminant: `enemy.behavior.${discriminant}`,
      spriteId
    })
  ),
  ...Object.entries(TRAP_STATE_SPRITE_MAP).map(([discriminant, spriteId]) => ({
    discriminant: `trap.${discriminant}`,
    spriteId
  })),
  { discriminant: "actor.player", spriteId: "actor.player" },
  { discriminant: "npc.any", spriteId: "npc.keeper" },
  { discriminant: "feature.hoard", spriteId: "feature.hoard" },
  { discriminant: "grid.empty", spriteId: "terrain.floor" }
] as const satisfies readonly {
  readonly discriminant: string;
  readonly spriteId: FallbackSpriteId;
}[];

export const resolveSpriteForCell = (
  state: GameState,
  cell: ArtResolverCellView,
  options: ArtResolverOptions = {}
): ResolvedSprite => {
  const position = { x: cell.x, y: cell.y };

  if (samePosition(state.player.position, position)) {
    return resolved(state, "actor.player", "actor.player", options);
  }

  const entities = entitiesAt(state, position);
  const enemy = entities.find((entity) => entity.kind === "enemy");
  if (enemy !== undefined) {
    return resolved(
      state,
      resolveEnemySpriteId(enemy.definition.behaviors[0]?.kind),
      `enemy.behavior.${enemy.definition.behaviors[0]?.kind ?? "default"}`,
      options
    );
  }

  const npc = entities.find((entity) => entity.kind === "npc");
  if (npc !== undefined) {
    return resolved(state, "npc.keeper", "npc.any", options);
  }

  const item = entities.find((entity) => entity.kind === "item");
  if (item !== undefined) {
    return resolved(
      state,
      resolveItemSpriteId(item.definition.kind),
      `item.${item.definition.kind}`,
      options
    );
  }

  const trap = entities.find((entity) => entity.kind === "trap");
  if (trap !== undefined) {
    const trapRevealed = isTrapRevealed(state, trap.id, trap.behaviorRuntime);
    if (trapRevealed || options.revealHiddenTraps === true) {
      return resolved(
        state,
        resolveTrapSpriteId(state, trap),
        trapRevealed ? "trap.revealed" : "trap.hidden",
        options
      );
    }
  }

  if (
    cell.featureKind === "hoard" ||
    hoardFeatureAt(state, position) !== null
  ) {
    return resolved(state, "feature.hoard", "feature.hoard", options);
  }

  return resolved(
    state,
    resolveTerrainSpriteId(cell.terrain),
    cell.layer === "empty" ? "grid.empty" : `terrain.${cell.terrain}`,
    options
  );
};

export const resolveSpriteForEntity = (
  state: GameState,
  entity: EntityInstance,
  options: ArtResolverOptions = {}
): ResolvedSprite => {
  switch (entity.kind) {
    case "enemy":
      return resolved(
        state,
        resolveEnemySpriteId(entity.definition.behaviors[0]?.kind),
        `enemy.behavior.${entity.definition.behaviors[0]?.kind ?? "default"}`,
        options
      );
    case "item":
      return resolved(
        state,
        resolveItemSpriteId(entity.definition.kind),
        `item.${entity.definition.kind}`,
        options
      );
    case "npc":
      return resolved(state, "npc.keeper", "npc.any", options);
    case "trap":
      return resolved(
        state,
        resolveTrapSpriteId(state, entity),
        isTrapRevealed(state, entity.id, entity.behaviorRuntime)
          ? "trap.revealed"
          : "trap.hidden",
        options
      );
  }
};

export const resolveTerrainSpriteId = (
  terrain: TerrainKind | string
): FallbackSpriteId =>
  isTerrainKind(terrain) ? TERRAIN_SPRITE_MAP[terrain] : "terrain.floor";

export const resolveItemSpriteId = (kind: ItemCategory): FallbackSpriteId =>
  ITEM_KIND_SPRITE_MAP[kind];

export const resolveEnemySpriteId = (
  behaviorKind: BehaviorKind | undefined
): FallbackSpriteId =>
  behaviorKind === undefined
    ? "enemy.brute"
    : ENEMY_BEHAVIOR_SPRITE_MAP[behaviorKind];

export const resolveTrapSpriteId = (
  state: GameState,
  trap: TrapEntityInstance
): FallbackSpriteId =>
  isTrapRevealed(state, trap.id, trap.behaviorRuntime)
    ? TRAP_STATE_SPRITE_MAP.revealed
    : TRAP_STATE_SPRITE_MAP.hidden;

const resolved = (
  state: GameState,
  spriteId: FallbackSpriteId,
  reason: string,
  options: ArtResolverOptions
): ResolvedSprite => ({
  spriteId,
  atlasKey: spriteAtlasKey(
    options.themeId ?? FALLBACK_THEME_ID,
    spriteId,
    options.seed ?? state.run.seed
  ),
  reason
});

const isTerrainKind = (value: string): value is TerrainKind =>
  value === Terrain.Floor ||
  value === Terrain.Wall ||
  value === Terrain.Door ||
  value === Terrain.Water ||
  value === Terrain.StairsDown ||
  value === Terrain.Entrance;

const ENTITY_KIND_ORDER: Readonly<Record<EntityInstance["kind"], number>> = {
  enemy: 0,
  item: 1,
  npc: 2,
  trap: 3
};

const entitiesAt = (
  state: GameState,
  position: Position
): readonly EntityInstance[] =>
  Object.values(state.entities)
    .filter((entity) => samePosition(entity.position, position))
    .sort(compareEntities);

const compareEntities = (
  left: EntityInstance,
  right: EntityInstance
): number => {
  const kindDelta =
    ENTITY_KIND_ORDER[left.kind] - ENTITY_KIND_ORDER[right.kind];

  if (kindDelta !== 0) {
    return kindDelta;
  }

  return compareEntityIds(left.id, right.id);
};

const compareEntityIds = (left: EntityId, right: EntityId): number => {
  const parsedLeft = parseEntityId(left);
  const parsedRight = parseEntityId(right);
  const kindOrder = parsedLeft.kind.localeCompare(parsedRight.kind);

  return kindOrder === 0 ? parsedLeft.index - parsedRight.index : kindOrder;
};

const parseEntityId = (
  id: EntityId
): { readonly kind: string; readonly index: number } => {
  const [kind, rawIndex] = id.split("#");

  return {
    kind: kind ?? "",
    index: Number.parseInt(rawIndex ?? "0", 10)
  };
};

const samePosition = (left: Position, right: Position): boolean =>
  left.x === right.x && left.y === right.y;

const hoardFeatureAt = (
  state: GameState,
  position: Position
): SerializableRecord | null => {
  for (const feature of decorativeFeatures(state)) {
    if (feature.kind !== "hoard") {
      continue;
    }

    if (feature.x === position.x && feature.y === position.y) {
      return feature;
    }
  }

  return null;
};

const decorativeFeatures = (
  state: GameState
): readonly SerializableRecord[] => {
  const opaque = state.floor.geometry.opaque as {
    readonly knowledge?: {
      readonly decorativeFeatures?: readonly SerializableRecord[];
    };
  } | null;

import {
  rasterizeSpriteManifest,
  type RasterizedSprite,
  type SpriteManifest
} from "./sprite-manifest.js";

export const FALLBACK_THEME_ID = "fallback";

export type SpriteAtlasThemeId = string | typeof FALLBACK_THEME_ID;

export type SpriteAtlasKey = {
  readonly themeId: SpriteAtlasThemeId;
  readonly entityId: string;
  readonly seed: string;
};

export type SpriteAtlasEntry = {
  readonly key: SpriteAtlasKey;
  readonly keyString: string;
  readonly manifest: SpriteManifest;
  readonly raster: RasterizedSprite;
};

export const spriteAtlasKey = (
  themeId: SpriteAtlasThemeId,
  entityId: string,
  seed: string
): SpriteAtlasKey => ({ themeId, entityId, seed });

export const serializeSpriteAtlasKey = (key: SpriteAtlasKey): string =>
  [key.themeId, key.entityId, key.seed].map(encodeKeyPart).join("|");

export const parseSpriteAtlasKey = (keyString: string): SpriteAtlasKey => {
  const parts = keyString.split("|");
  if (parts.length !== 3) {
    throw new Error(`invalid sprite atlas key: ${keyString}`);
  }

  const [themeId, entityId, seed] = parts.map(decodeKeyPart);
  if (
    themeId === undefined ||
    entityId === undefined ||
    seed === undefined ||
    themeId.length === 0 ||
    entityId.length === 0 ||
    seed.length === 0
  ) {
    throw new Error(`invalid sprite atlas key: ${keyString}`);
  }

  return { themeId, entityId, seed };
};

export class SpriteAtlasCache {
  readonly #entries = new Map<string, SpriteAtlasEntry>();

  get size(): number {
    return this.#entries.size;
  }

  has(key: SpriteAtlasKey): boolean {
    return this.#entries.has(serializeSpriteAtlasKey(key));
  }

  get(key: SpriteAtlasKey): SpriteAtlasEntry | null {
    return this.#entries.get(serializeSpriteAtlasKey(key)) ?? null;
  }

  set(
    key: SpriteAtlasKey,
    manifest: SpriteManifest,
    options: { readonly scale?: number } = {}
  ): SpriteAtlasEntry {
    const keyString = serializeSpriteAtlasKey(key);
    const entry = {
      key,
      keyString,
      manifest,
      raster: rasterizeSpriteManifest(manifest, options)
    } as const satisfies SpriteAtlasEntry;

    this.#entries.set(keyString, entry);

    return entry;
  }

  getOrSet(
    key: SpriteAtlasKey,
    manifest: SpriteManifest,
    options: { readonly scale?: number } = {}
  ): SpriteAtlasEntry {
    const existing = this.get(key);

    return existing ?? this.set(key, manifest, options);
  }

  entries(): readonly SpriteAtlasEntry[] {
    return [...this.#entries.values()].sort((left, right) =>
      left.keyString.localeCompare(right.keyString)
    );
  }

  clear(): void {
    this.#entries.clear();
  }
}

const encodeKeyPart = (part: string): string => encodeURIComponent(part);

const decodeKeyPart = (part: string): string => decodeURIComponent(part);

