const buildJudgePrompt = (prompt: string): string =>
  [
    "Return ONLY one JSON object with this exact shape:",
    '{"verdict":"pass|fail|uncertain","reason":"short reason","score":0.5}',
    "Use a numeric score from 0 to 1, or null when no score applies.",
    prompt,
  ].join("\n");

const parseJudgeResult = (raw: string, usage: ProviderUsage): JudgeResult => {
  const extracted = extractFirstJsonObject(raw);
  if (!extracted.ok) {
    return failure("parse_fail", extracted.message, usage, raw);
  }

  let parsed: unknown;
  try {
    parsed = JSON.parse(extracted.json);
  } catch (error) {
    return failure(
      "parse_fail",
      error instanceof Error ? `invalid JSON: ${error.message}` : "invalid JSON",
      usage,
      raw,
    );
  }

  const verdict = JudgeVerdictSchema.safeParse(parsed);
  if (!verdict.success) {
    return failure(
      "validate_fail",
      "judge output did not match verdict schema",
      usage,
      raw,
      verdict.error.issues.map((issue) => issue.message),
    );
  }

  return {
    ok: true,
    raw,
    verdict: verdict.data satisfies JudgeVerdict,
    usage,
  };
};

const extractFirstJsonObject = (
  raw: string,
):
  | { readonly ok: true; readonly json: string }
  | { readonly ok: false; readonly message: string } => {
  const text = stripMarkdownFence(raw);
  const start = text.indexOf("{");
  if (start === -1) {
    return { ok: false, message: "no JSON object found" };
  }

  let depth = 0;
  let inString = false;
  let escaping = false;

  for (let index = start; index < text.length; index += 1) {
    const char = text[index];

    if (inString) {
      if (escaping) {
        escaping = false;
        continue;
      }

      if (char === "\\") {
        escaping = true;
        continue;
      }

      if (char === '"') {
        inString = false;
      }
      continue;
    }

    if (char === '"') {
      inString = true;
      continue;
    }

    if (char === "{") {
      depth += 1;
      continue;
    }

    if (char === "}") {
      depth -= 1;
      if (depth === 0) {
        return { ok: true, json: text.slice(start, index + 1) };
      }
    }
  }

  return { ok: false, message: "unterminated JSON object" };
};

const stripMarkdownFence = (raw: string): string => {
  const trimmed = raw.trim();
  const fenced = trimmed.match(/^```[a-zA-Z0-9_-]*\s*\n?([\s\S]*?)\n?```$/);
  return fenced?.[1]?.trim() ?? trimmed;
};

export const formatSpriteValidationErrors = (
  errors: readonly SpriteValidationError[]
): string =>
  errors.map((error) => `${error.path}: ${error.message}`).join("; ");

export const spriteManifestStats = (
  manifest: SpriteManifest
): SpriteManifestStats =>
  spriteManifestStatsForShape(manifest.w, manifest.h, manifest.px);

export const rasterizeSpriteManifest = (
  manifest: SpriteManifest,
  options: { readonly scale?: number } = {}
): RasterizedSprite => {
  const scale = options.scale ?? 1;

  if (!Number.isInteger(scale) || scale < 1 || scale > 32) {
    throw new Error("scale must be an integer from 1 to 32");
  }

  const validated = validateSpriteManifest(manifest);
  if (!validated.ok) {
    throw new Error(
      `invalid sprite manifest: ${formatSpriteValidationErrors(
        validated.errors
      )}`
    );
  }

  const width = manifest.w * scale;
  const height = manifest.h * scale;
  const pixels = new Uint8ClampedArray(width * height * 4);
  const colors = manifest.palette.map(parseHexRgb);

  for (let sourceY = 0; sourceY < manifest.h; sourceY += 1) {
    const row = manifest.px[sourceY];
    if (row === undefined) {
      throw new Error(`missing sprite row ${sourceY}`);
    }

    for (let sourceX = 0; sourceX < manifest.w; sourceX += 1) {
      const paletteIndex = row[sourceX] ?? 0;
      if (paletteIndex === 0) {
        continue;
      }

      const color = colors[paletteIndex - 1];
      if (color === undefined) {
        throw new Error(`missing palette color ${paletteIndex}`);
      }

      for (let offsetY = 0; offsetY < scale; offsetY += 1) {
        for (let offsetX = 0; offsetX < scale; offsetX += 1) {
          const targetX = sourceX * scale + offsetX;
          const targetY = sourceY * scale + offsetY;
          const targetOffset = (targetY * width + targetX) * 4;
          pixels[targetOffset] = color.red;
          pixels[targetOffset + 1] = color.green;
          pixels[targetOffset + 2] = color.blue;
          pixels[targetOffset + 3] = 255;
        }
      }
    }
  }

  return { width, height, scale, pixels };
};

const isAllowedSize = (value: unknown): value is SpriteSize =>
  value === 16 || value === 24;

const isPlainObject = (
  value: unknown
): value is { readonly [key: string]: unknown } =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const spriteManifestStatsForShape = (
  width: number,
  height: number,
  px: readonly unknown[]
): SpriteManifestStats => {
  let filledPixels = 0;
  const visibleColors = new Set<number>();
  const occupiedRows = new Set<number>();
  const occupiedColumns = new Set<number>();

  px.forEach((row, y) => {
    if (!Array.isArray(row)) {
      return;
    }

    row.forEach((cell, x) => {
      if (Number.isInteger(cell) && cell > 0) {
        filledPixels += 1;
        visibleColors.add(cell);
        occupiedRows.add(y);
        occupiedColumns.add(x);
      }
    });
  });

  const totalPixels = width * height;

  return {
    totalPixels,
    filledPixels,
    filledRatio: filledPixels / totalPixels,
    visibleColorCount: visibleColors.size,
    occupiedRows: occupiedRows.size,
    occupiedColumns: occupiedColumns.size
  };
};

const parseHexRgb = (
  hex: HexColor
): { readonly red: number; readonly green: number; readonly blue: number } => ({
  red: Number.parseInt(hex.slice(1, 3), 16),
  green: Number.parseInt(hex.slice(3, 5), 16),
  blue: Number.parseInt(hex.slice(5, 7), 16)
});

  } | null;

  return opaque?.knowledge?.decorativeFeatures ?? [];
};

