export class GenerationRecordExistsError extends Error {
  readonly code = "GENERATION_RECORD_EXISTS" as const;

  constructor(runId: string, depth: number) {
    super(`generation record already exists for run ${runId} floor ${depth}`);
    this.name = "GenerationRecordExistsError";
  }
}

export type WriteGenerationRecordOptions = {
  readonly rootDir?: string;
  readonly fs?: ArtifactFsAdapter;
};

const GENERATION_RECORD_FILE = "generation.json";
const INDEX_FILE = "index.json";
const INDEX_TEMP_SUFFIX = ".tmp";

export const generationRecordPath = (
  runId: string,
  depth: number,
  rootDir = "runs",
): string =>
  `${trimTrailingSlash(rootDir)}/${runId}/floors/${depth}/${GENERATION_RECORD_FILE}`;

export const runIndexPath = (runId: string, rootDir = "runs"): string =>
  `${trimTrailingSlash(rootDir)}/${runId}/${INDEX_FILE}`;

const toOutcomeSummary = (
  outcome: GenerationOutcome,
): GenerationOutcomeSummary =>
  outcome.kind === "manifest"
    ? { kind: "manifest" }
    : { kind: "fallback", fallbackId: outcome.fallbackId };

const relativeRunPath = (runDir: string, absolutePath: string): string => {
  const prefix = `${runDir}/`;
  if (!absolutePath.startsWith(prefix)) {
    throw new Error(`path is not under run directory: ${absolutePath}`);
  }
  return absolutePath.slice(prefix.length);
};

const buildProviderSnapshot = (
  providerResult: GenerationAttemptInput["providerResult"],
  manifestPath?: string,
): AttemptProviderSnapshot => {
  if (providerResult.ok) {
    return {
      ok: true,
      usage: providerResult.usage,
      ...(manifestPath === undefined ? {} : { manifestPath }),
    };
  }

  return {
    ok: false,
    usage: providerResult.usage,
    error: providerResult.error,
  };
};

const persistAttemptArtifacts = (
  fs: ArtifactFsAdapter,
  runDir: string,
  floorDir: string,
  attemptIndex: number,
  attempt: GenerationAttemptInput,
): GenerationAttemptRecord => {
  const attemptDir = `${floorDir}/attempts/${attemptIndex}`;
  fs.makeDir(attemptDir);

  const rawOutputPath = `${attemptDir}/raw.txt`;
  const raw =
    attempt.providerResult.ok === true
      ? attempt.providerResult.raw
      : (attempt.providerResult.raw ?? "");
  fs.writeNewFile(rawOutputPath, raw);

  let manifestRelativePath: string | undefined;
  if (attempt.providerResult.ok) {
    const manifestPath = `${attemptDir}/manifest.json`;
    fs.writeNewFile(
      manifestPath,
      `${JSON.stringify(attempt.providerResult.manifest, null, 2)}\n`,
    );
    manifestRelativePath = relativeRunPath(runDir, manifestPath);
  }

  return {
    attemptIndex,
    promptHash: hashPrompt(attempt.prompt),
    rawOutputPath: relativeRunPath(runDir, rawOutputPath),
    provider: buildProviderSnapshot(
      attempt.providerResult,
      manifestRelativePath,
    ),
    ...(attempt.gateReports === undefined
      ? {}
      : { gateReports: attempt.gateReports }),
  };
};

const loadOrCreateIndex = (
  fs: ArtifactFsAdapter,
  runDir: string,
  input: WriteGenerationRecordInput,
): RunGenerationIndex => {
  const indexPath = `${runDir}/${INDEX_FILE}`;
  if (!fs.fileExists(indexPath)) {
    return {
      recordType: "generation-index",
      protocolVersion: PROTOCOL_VERSION,
      engineVersion: ENGINE_VERSION,
      modelId: input.modelId,
      seed: input.seed,
      createdAt: input.createdAt,
      runId: input.runId,
      updatedAt: input.recordedAt,
      floors: [],
    };
  }

  return JSON.parse(fs.readFile(indexPath)) as RunGenerationIndex;
};

const writeIndexAtomically = (
  fs: ArtifactFsAdapter,
  indexPath: string,
  index: RunGenerationIndex,
): void => {
  const tempPath = `${indexPath}${INDEX_TEMP_SUFFIX}`;
  fs.writeFile(tempPath, `${JSON.stringify(index, null, 2)}\n`);
  fs.rename(tempPath, indexPath);
};

export const writeGenerationRecord = (
  input: WriteGenerationRecordInput,
  options: WriteGenerationRecordOptions = {},
): GenerationRecord => {
  const rootDir = trimTrailingSlash(options.rootDir ?? "runs");
  const fs = options.fs ?? nodeArtifactFsAdapter;
  const runDir = `${rootDir}/${input.runId}`;
  const floorDir = `${runDir}/floors/${input.depth}`;
  const recordPath = `${floorDir}/${GENERATION_RECORD_FILE}`;

  if (fs.fileExists(recordPath)) {
    throw new GenerationRecordExistsError(input.runId, input.depth);
  }

  fs.makeDir(floorDir);

  const attempts = input.attempts.map((attempt, attemptIndex) =>
    persistAttemptArtifacts(fs, runDir, floorDir, attemptIndex, attempt),
  );

  const outcome =
    input.outcome.kind === "manifest"
      ? {
          kind: "manifest" as const,
          manifestPath: relativeRunPath(runDir, input.outcome.manifestPath),
        }
      : input.outcome;

  const record: GenerationRecord = {
    recordType: "generation",
    protocolVersion: PROTOCOL_VERSION,
    engineVersion: ENGINE_VERSION,
    modelId: input.modelId,
    seed: input.seed,
    createdAt: input.createdAt,
    runId: input.runId,
    depth: input.depth,
    attempts,
    outcome,
  };

  fs.writeNewFile(recordPath, `${JSON.stringify(record, null, 2)}\n`);

  const index = loadOrCreateIndex(fs, runDir, input);
  const recordRelativePath = relativeRunPath(runDir, recordPath);
  const floorEntry: FloorIndexEntry = {
    depth: input.depth,
    recordPath: recordRelativePath,
    outcome: toOutcomeSummary(input.outcome),
    recordedAt: input.recordedAt,
  };
  const nextFloors = [
    ...index.floors.filter((entry) => entry.depth !== input.depth),
    floorEntry,
  ].sort((left, right) => left.depth - right.depth);
  const nextIndex: RunGenerationIndex = {
    ...index,
    modelId: input.modelId,
    seed: input.seed,
    updatedAt: input.recordedAt,
    floors: nextFloors,
  };

  writeIndexAtomically(fs, `${runDir}/${INDEX_FILE}`, nextIndex);

  return record;
};

const offendingFragments = (
  providerResult: ProviderResult,
  manifest: FloorManifest | undefined
): readonly string[] => {
  const raw = providerResult.ok ? providerResult.raw : providerResult.raw;
  if (raw !== undefined && raw.trim().length > 0) {
    return [truncateFragment(raw)];
  }

  if (manifest !== undefined) {
    return [truncateFragment(JSON.stringify(manifest, null, 2))];
  }

  return [];
};

const truncateFragment = (fragment: string): string =>
  fragment.length <= FRAGMENT_MAX_CHARS
    ? fragment
    : `${fragment.slice(0, FRAGMENT_MAX_CHARS)}\n...<truncated>`;

const serveFallback = (
  ctx: GenerateFloorContext,
  attempts: readonly GenerationAttemptInput[]
): GenerateFloorResult => {
  const fallbackProvider =
    ctx.fallbackProvider ?? createFallbackFloorContentProvider();
  const floor = fallbackProvider.getFloor(ctx.depth, ctx.seed);
  const record = writeRecord(ctx, attempts, {
    kind: "fallback",
    fallbackId: fallbackId(ctx.depth, floor)
  });

  return { floor, record };
};

const fallbackId = (depth: number, floor: FloorContent): string =>
  `fallback:old-stock:${floor.params.bandOrSize}-${depth}`;

const writeRecord = (
  ctx: GenerateFloorContext,
  attempts: readonly GenerationAttemptInput[],
  outcome: Parameters<typeof writeGenerationRecord>[0]["outcome"]
): GenerationRecord => {
  const createdAt = ctx.createdAt ?? ctx.now?.() ?? new Date().toISOString();
  const recordedAt = ctx.recordedAt ?? ctx.now?.() ?? createdAt;

  return writeGenerationRecord(
    {
      runId: ctx.runId,
      depth: ctx.depth,
      seed: ctx.seed,
      modelId: ctx.modelId,
      createdAt,
      recordedAt,
      attempts,
      outcome
    },
    ctx.artifacts
  );
};

const servedManifestPath = (
  ctx: GenerateFloorContext,
  attemptIndex: number
): string => {
  const rootDir = trimTrailingSlash(ctx.artifacts?.rootDir ?? DEFAULT_ROOT_DIR);
  return `${rootDir}/${ctx.runId}/floors/${ctx.depth}/attempts/${attemptIndex}/manifest.json`;
};

const trimTrailingSlash = (value: string): string => value.replace(/\/+$/g, "");

import {
  mkdirSync,
  readdirSync,
  readFileSync,
  renameSync,
  statSync,
  writeFileSync,
} from "node:fs";
export type ArtifactFsAdapter = {
  readonly makeDir: (path: string) => void;
  readonly writeNewFile: (path: string, contents: string) => void;
  readonly writeFile: (path: string, contents: string) => void;
  readonly readFile: (path: string) => string;
  readonly fileExists: (path: string) => boolean;
  readonly rename: (from: string, to: string) => void;
  readonly listEntries: (path: string) => readonly string[];
  readonly isDirectory: (path: string) => boolean;
};

export const trimTrailingSlash = (value: string): string =>
  value.replace(/\/+$/g, "");

export const nodeArtifactFsAdapter: ArtifactFsAdapter = {
  makeDir: (path) => {
    mkdirSync(path, { recursive: true });
  },
  writeNewFile: (path, contents) => {
    writeFileSync(path, contents, { encoding: "utf8", flag: "wx" });
  },
  writeFile: (path, contents) => {
    writeFileSync(path, contents, { encoding: "utf8" });
  },
  readFile: (path) => readFileSync(path, { encoding: "utf8" }),
  fileExists: (path) => {
    try {
      statSync(path);
      return true;
    } catch {
      return false;
    }
  },
  rename: (from, to) => {
    renameSync(from, to);
  },
  listEntries: (path) => readdirSync(path),
  isDirectory: (path) => statSync(path).isDirectory(),
};

export class MemoryArtifactFs implements ArtifactFsAdapter {
  readonly dirs = new Set<string>();
  readonly files = new Map<string, string>();

  makeDir(path: string): void {
    this.dirs.add(path);
  }

  writeNewFile(path: string, contents: string): void {
    if (this.files.has(path)) {
      throw new Error(`file already exists: ${path}`);
    }
    this.files.set(path, contents);
  }

  writeFile(path: string, contents: string): void {
    this.files.set(path, contents);
  }

  readFile(path: string): string {
    const contents = this.files.get(path);
    if (contents === undefined) {
      throw new Error(`file does not exist: ${path}`);
    }
    return contents;
  }

  fileExists(path: string): boolean {
    return this.files.has(path);
  }

  rename(from: string, to: string): void {
    const contents = this.files.get(from);
    if (contents === undefined) {
      throw new Error(`file does not exist: ${from}`);
    }
    this.files.set(to, contents);
    this.files.delete(from);
  }

  listEntries(path: string): readonly string[] {
    const prefix = `${path}/`;
    const entries = new Set<string>();

    for (const filePath of this.files.keys()) {
      if (!filePath.startsWith(prefix)) {
        continue;
      }
      const remainder = filePath.slice(prefix.length);
      const [entry] = remainder.split("/");
      if (entry !== undefined && entry.length > 0) {
        entries.add(entry);
      }
    }

    for (const dirPath of this.dirs) {
      if (!dirPath.startsWith(prefix)) {
        continue;
      }
      const remainder = dirPath.slice(prefix.length);
      const [entry] = remainder.split("/");
      if (entry !== undefined && entry.length > 0) {
        entries.add(entry);
      }
    }

    return [...entries].sort();
  }

  isDirectory(path: string): boolean {
    if (this.dirs.has(path)) {
      return true;
    }

    const prefix = `${path}/`;
    return [...this.files.keys(), ...this.dirs].some((candidate) =>
      candidate.startsWith(prefix),
    );
  }
}

import {
  nodeArtifactFsAdapter,
  trimTrailingSlash,
  type ArtifactFsAdapter,
} from "./fs.js";
import type {
  FloorIndexEntry,
  GenerationRecord,
  RunGenerationIndex,
  RunGenerationSummary,
} from "./types.js";

export type ArtifactReadOptions = {
  readonly rootDir?: string;
  readonly fs?: ArtifactFsAdapter;
};

const INDEX_FILE = "index.json";

const resolveReadContext = (options: ArtifactReadOptions = {}) => ({
  rootDir: trimTrailingSlash(options.rootDir ?? "runs"),
  fs: options.fs ?? nodeArtifactFsAdapter,
});

const loadRunIndexFile = (
  fs: ArtifactFsAdapter,
  rootDir: string,
  runId: string,
): RunGenerationIndex => {
  const indexPath = `${rootDir}/${runId}/${INDEX_FILE}`;
  if (!fs.fileExists(indexPath)) {
    throw new Error(`generation index not found for run: ${runId}`);
  }

  return JSON.parse(fs.readFile(indexPath)) as RunGenerationIndex;
};

export const listRuns = (
  options: ArtifactReadOptions = {},
): readonly RunGenerationSummary[] => {
  const { rootDir, fs } = resolveReadContext(options);
  if (!fs.isDirectory(rootDir)) {
    return [];
  }

  const summaries: RunGenerationSummary[] = [];

  for (const runId of fs.listEntries(rootDir)) {
    const indexPath = `${rootDir}/${runId}/${INDEX_FILE}`;
    if (!fs.fileExists(indexPath)) {
      continue;
    }

    const index = JSON.parse(fs.readFile(indexPath)) as RunGenerationIndex;
    if (index.recordType !== "generation-index") {
      continue;
    }

    summaries.push({
      runId: index.runId,
      stamp: {
        recordType: "generation-stamp",
        protocolVersion: index.protocolVersion,
        engineVersion: index.engineVersion,
        modelId: index.modelId,
        seed: index.seed,
        createdAt: index.createdAt,
      },
      updatedAt: index.updatedAt,
      floorCount: index.floors.length,
    });
  }

  return summaries.sort((left, right) =>
    right.updatedAt.localeCompare(left.updatedAt),
  );
};

export const listFloors = (
  runId: string,
  options: ArtifactReadOptions = {},
): readonly FloorIndexEntry[] => {
  const { rootDir, fs } = resolveReadContext(options);
  const index = loadRunIndexFile(fs, rootDir, runId);
  return [...index.floors].sort((left, right) => left.depth - right.depth);
};

export const loadGenerationChain = (
  runId: string,
  depth: number,
  options: ArtifactReadOptions = {},
): GenerationRecord => {
  const { rootDir, fs } = resolveReadContext(options);
  const index = loadRunIndexFile(fs, rootDir, runId);
  const floorEntry = index.floors.find((entry) => entry.depth === depth);
  if (floorEntry === undefined) {
    throw new Error(
      `generation record not indexed for run ${runId} floor ${depth}`,
    );
  }

  const recordPath = `${rootDir}/${runId}/${floorEntry.recordPath}`;
  if (!fs.fileExists(recordPath)) {
    throw new Error(`generation record missing at ${recordPath}`);
  }

  return JSON.parse(fs.readFile(recordPath)) as GenerationRecord;
};

export const readRunIndex = (
  runId: string,
  options: ArtifactReadOptions = {},
): RunGenerationIndex => {
  const { rootDir, fs } = resolveReadContext(options);
  return loadRunIndexFile(fs, rootDir, runId);
};

import type { DirectorProviderSelection } from "../../config/index.js";
import type {
  FloorManifest,
  ManifestParseError,
} from "../../schemas/manifest.js";

export type DirectorProviderKind = DirectorProviderSelection;

export type ProviderFailureCode =
  | "timeout"
  | "process_error"
  | "parse_fail"
  | "validate_fail";

export type ProviderTokenUsage = {
  readonly inputTokens?: number | null;
  readonly outputTokens?: number | null;
  readonly totalTokens?: number | null;
};

export type ProviderUsage = {
  readonly latencyMs: number;
  readonly tokens?: ProviderTokenUsage | null;
};

export type ProviderError = {
  readonly code: ProviderFailureCode;
  readonly message: string;
  readonly details?: readonly string[];
};

export type ProviderSuccess = {
  readonly ok: true;
  readonly raw: string;
  readonly manifest: FloorManifest;
  readonly usage: ProviderUsage;
};

export type ProviderFailure = {
  readonly ok: false;
  readonly error: ProviderError;
  readonly raw?: string;
  readonly usage: ProviderUsage;
};

export type ProviderResult = ProviderSuccess | ProviderFailure;

export type JudgeVerdictLabel = "pass" | "fail" | "uncertain";

export type JudgeVerdict = {
  readonly verdict: JudgeVerdictLabel;
  readonly reason: string;
  readonly score: number | null;
};

export type JudgeSuccess = {
  readonly ok: true;
  readonly raw: string;
  readonly verdict: JudgeVerdict;
  readonly usage: ProviderUsage;
};

export type JudgeFailure = {
  readonly ok: false;
  readonly error: ProviderError;
  readonly raw?: string;
  readonly usage: ProviderUsage;
};

export type JudgeResult = JudgeSuccess | JudgeFailure;

export type GenerateManifestOptions = {
  readonly timeoutMs?: number;
};

export type JudgeOptions = {
  readonly timeoutMs?: number;
};

export interface DirectorProvider {
  generateManifest(
    prompt: string,
    options?: GenerateManifestOptions,
  ): Promise<ProviderResult>;

  judge(prompt: string, options?: JudgeOptions): Promise<JudgeResult>;
}

export type ProviderClock = () => number;

export const failure = (
  code: ProviderFailureCode,
  message: string,
  usage: ProviderUsage,
  raw?: string,
  details?: readonly string[],
): ProviderFailure => ({
  ok: false,
  error: {
    code,
    message,
    ...(details === undefined ? {} : { details }),
  },
  ...(raw === undefined ? {} : { raw }),
  usage,
});

export const manifestFailureCodeFor = (
  errors: readonly ManifestParseError[],
): ProviderFailureCode => {
  if (
    errors.length === 1 &&
    errors[0]?.path === "$" &&
    isJsonParseMessage(errors[0].message)
  ) {
    return "parse_fail";
  }

  return "validate_fail";
};

const isJsonParseMessage = (message: string): boolean =>
  message === "no JSON object found" ||
  message === "unterminated JSON object" ||
  message.startsWith("invalid JSON:");

export {
