const runProcess = ({
  command,
  args,
  timeoutMs,
  exec,
  now,
}: {
  readonly command: string;
  readonly args: readonly string[];
  readonly timeoutMs: number;
  readonly exec: ArtProviderExec;
  readonly now: () => number;
}): Promise<ProcessRunResult> =>
  new Promise((resolve) => {
    const startedAt = now();
    const stdoutChunks: string[] = [];
    const stderrChunks: string[] = [];
    let settled = false;
    let child: ArtProviderProcess;

    const usage = (): ArtDirectorProviderUsage => ({
      latencyMs: Math.max(0, now() - startedAt),
      tokens: null,
    });

    const finish = (result: ProcessRunResult): void => {
      if (settled) {
        return;
      }

      settled = true;
      clearTimeout(timeout);
      resolve(result);
    };

    const timeout = setTimeout(() => {
      const stdout = stdoutChunks.join("");
      const stderr = stderrChunks.join("");
      const killed = child.kill("SIGTERM");
      finish({
        ok: false,
        code: "timeout",
        message: `process timed out after ${timeoutMs}ms; killed=${killed}`,
        stdout,
        stderr,
        usage: usage(),
      });
    }, timeoutMs);

    try {
      child = exec(command, args, { stdin: "ignore" });
    } catch (error) {
      finish({
        ok: false,
        code: "process_error",
        message: error instanceof Error ? error.message : String(error),
        stdout: "",
        stderr: "",
        usage: usage(),
      });
      return;
    }

    child.stdout.setEncoding?.("utf8");
    child.stderr.setEncoding?.("utf8");

    child.stdout.on("data", (chunk) => {
      stdoutChunks.push(String(chunk));
    });

    child.stderr.on("data", (chunk) => {
      stderrChunks.push(String(chunk));
    });

    child.on("error", (error) => {
      finish({
        ok: false,
        code: "process_error",
        message: error.message,
        stdout: stdoutChunks.join(""),
        stderr: stderrChunks.join(""),
        usage: usage(),
      });
    });

    child.on("close", (code, signal) => {
      const stdout = stdoutChunks.join("");
      const stderr = stderrChunks.join("");

      if (code === 0) {
        finish({
          ok: true,
          stdout,
          stderr,
          usage: usage(),
        });
        return;
      }

      finish({
        ok: false,
        code: "process_error",
        message: `process exited with code ${code ?? "null"} signal ${
          signal ?? "null"
        }${stderr.length === 0 ? "" : `: ${stderr}`}`,
        stdout,
        stderr,
        usage: usage(),
      });
    });
  });
import {
  MAX_PALETTE_COLORS,
  MIN_FILLED_RATIO,
  formatSpriteValidationErrors,
  rasterizeSpriteManifest,
  spriteManifestStats,
  validateSpriteManifest,
  type SpriteManifest,
} from "../art/sprite-manifest.js";
import type {
  ArtGauntletReport,
  ArtGauntletStage,
  ArtGauntletStageReport,
} from "./types.js";

const NORMAL_PALETTE_MAX = 6;
const SIGNATURE_PALETTE_MAX = 8;

export type RunArtGauntletOptions = {
  readonly role?: string;
  readonly scale?: number;
};

export const runArtGauntlet = (
  candidate: unknown,
  options: RunArtGauntletOptions = {},
): ArtGauntletReport => {
  const stages: ArtGauntletStageReport[] = [];
  const validated = validateSpriteManifest(candidate);

  if (!validated.ok) {
    return reject("schema", formatSpriteValidationErrors(validated.errors), [
      ...stages,
      {
        stage: "schema",
        ok: false,
        details: validated.errors.map(
          (error) => `${error.path}: ${error.message}`,
        ),
      },
    ]);
  }

  const manifest = validated.manifest;
  stages.push({ stage: "schema", ok: true, details: [] });

  const palette = checkPaletteBudget(manifest, options.role);
  stages.push(palette);
  if (!palette.ok) {
    return reject("palette", palette.details.join("; "), stages);
  }

  try {
    rasterizeSpriteManifest(manifest, { scale: options.scale ?? 1 });
    stages.push({ stage: "render", ok: true, details: [] });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    stages.push({ stage: "render", ok: false, details: [message] });
    return reject("render", message, stages);
  }

  const readability = checkReadability(manifest);
  stages.push(readability);
  if (!readability.ok) {
    return reject("readability", readability.details.join("; "), stages);
  }

  return { ok: true, manifest, stages };
};

const checkPaletteBudget = (
  manifest: SpriteManifest,
  role: string | undefined,
): ArtGauntletStageReport => {
  const max =
    role === "signature" || role === "boss"
      ? SIGNATURE_PALETTE_MAX
      : NORMAL_PALETTE_MAX;

  if (manifest.palette.length > MAX_PALETTE_COLORS) {
    return {
      stage: "palette",
      ok: false,
      details: [`palette exceeds hard max ${MAX_PALETTE_COLORS}`],
    };
  }

  if (manifest.palette.length > max) {
    return {
      stage: "palette",
      ok: false,
      details: [
        `palette has ${manifest.palette.length} colors; ${role ?? "normal"} max is ${max}`,
      ],
    };
  }

  return { stage: "palette", ok: true, details: [] };
};

const checkReadability = (
  manifest: SpriteManifest,
): ArtGauntletStageReport => {
  const stats = spriteManifestStats(manifest);
  const details: string[] = [];

  if (stats.filledRatio < MIN_FILLED_RATIO) {
    details.push(
      `filled ratio ${stats.filledRatio.toFixed(3)} below ${MIN_FILLED_RATIO}`,
    );
  }

  if (stats.occupiedRows < 3) {
    details.push(`occupied rows ${stats.occupiedRows} below 3`);
  }

  if (stats.occupiedColumns < 3) {
    details.push(`occupied columns ${stats.occupiedColumns} below 3`);
  }

  if (stats.visibleColorCount < 2) {
    details.push(`visible colors ${stats.visibleColorCount} below 2`);
  }

  return {
    stage: "readability",
    ok: details.length === 0,
    details,
  };
};

const reject = (
  rejectedAt: ArtGauntletStage,
  reason: string,
  stages: readonly ArtGauntletStageReport[],
): ArtGauntletReport => ({
  ok: false,
  rejectedAt,
  reason,
  stages,
});

import type {
  ArtDirector,
  ArtDirectorAcceptedSprite,
  ArtDirectorBatchRequest,
  ArtDirectorBatchResult,
  ArtDirectorRejectedSprite,
  ArtDirectorSpriteRequest,
} from "../art/art-director.js";
import {
  serializeSpriteAtlasKey,
  spriteAtlasKey,
  SpriteAtlasCache,
} from "../art/atlas.js";
import { buildArtDirectorPrompt } from "./prompt.js";
import { AmbientArtDirectorProvider } from "./provider.js";
import { runArtGauntlet } from "./gauntlet.js";
import {
  writeArtDirectorAttemptArtifact,
  type ArtDirectorArtifactOptions,
} from "./artifacts.js";
import type {
  ArtDirectorProviderResult,
  ArtDirectorSpriteProvider,
} from "./types.js";

export type ArtDirectorMode = "generate" | "fallback";

export type AmbientArtDirectorOptions = {
  readonly provider?: ArtDirectorSpriteProvider;
  readonly atlas?: SpriteAtlasCache;
  readonly mode?: ArtDirectorMode;
  readonly timeoutMs?: number;
  readonly artifacts?: ArtDirectorArtifactOptions;
  readonly now?: () => string;
};

export class AmbientArtDirector implements ArtDirector {
  private readonly provider: ArtDirectorSpriteProvider;
  private readonly atlas: SpriteAtlasCache;
  private readonly mode: ArtDirectorMode;
  private readonly timeoutMs: number | undefined;
  private readonly artifacts: ArtDirectorArtifactOptions | undefined;
  private readonly now: () => string;
  private readonly sourcePaths = new Map<string, string>();

  constructor(options: AmbientArtDirectorOptions = {}) {
    this.provider = options.provider ?? new AmbientArtDirectorProvider();
    this.atlas = options.atlas ?? new SpriteAtlasCache();
    this.mode = options.mode ?? artDirectorModeFromEnv();
    this.timeoutMs = options.timeoutMs;
    this.artifacts = options.artifacts;
    this.now = options.now ?? (() => new Date().toISOString());
  }

  async generateSprites(
    request: ArtDirectorBatchRequest,
  ): Promise<ArtDirectorBatchResult> {
    const accepted: ArtDirectorAcceptedSprite[] = [];
    const rejected: ArtDirectorRejectedSprite[] = [];

    for (const sprite of request.sprites) {
      const atlasKey = spriteAtlasKey(
        request.themeId,
        sprite.entityId,
        request.seed,
      );
      const atlasKeyString = serializeSpriteAtlasKey(atlasKey);
      const cached = this.atlas.get(atlasKey);
      if (cached !== null) {
        accepted.push({
          entityId: sprite.entityId,
          atlasKey,
          manifest: cached.manifest,
          sourceArtifactPath:
            this.sourcePaths.get(atlasKeyString) ?? "atlas-cache",
        });
        continue;
      }

      if (this.mode === "fallback") {
        rejected.push({
          entityId: sprite.entityId,
          fallbackSpriteId: sprite.fallbackSpriteId,
          reason: "ART=fallback",
          sourceArtifactPath: null,
        });
        continue;
      }

      const prompt = buildArtDirectorPrompt({
        themeId: request.themeId,
        entityId: sprite.entityId,
        entityPrompt: sprite.prompt,
        role: sprite.role,
        size: sprite.size,
        paletteHint: sprite.paletteHint,
      });
      const providerResult = await this.provider.generateSprite(prompt, {
        ...(this.timeoutMs === undefined ? {} : { timeoutMs: this.timeoutMs }),
      });
      const result = this.applyProviderResult({
        request,
        sprite,
        prompt,
        providerResult,
      });

      if (result.kind === "accepted") {
        accepted.push(result.accepted);
      } else {
        rejected.push(result.rejected);
      }
    }

    return { accepted, rejected };
  }

  private applyProviderResult({
    request,
    sprite,
    prompt,
    providerResult,
  }: {
    readonly request: ArtDirectorBatchRequest;
    readonly sprite: ArtDirectorSpriteRequest;
    readonly prompt: string;
    readonly providerResult: ArtDirectorProviderResult;
  }):
    | { readonly kind: "accepted"; readonly accepted: ArtDirectorAcceptedSprite }
    | { readonly kind: "rejected"; readonly rejected: ArtDirectorRejectedSprite } {
    const atlasKey = spriteAtlasKey(
      request.themeId,
      sprite.entityId,
      request.seed,
    );

    if (!providerResult.ok) {
      const path = this.writeAttempt({
        request,
        sprite,
        prompt,
        providerResult,
        gauntlet: null,
        reason: providerResult.error.message,
      });
      return {
        kind: "rejected",
        rejected: {
          entityId: sprite.entityId,
          fallbackSpriteId: sprite.fallbackSpriteId,
          reason: providerResult.error.message,
          sourceArtifactPath: path,
        },
      };
    }

    const gauntlet = runArtGauntlet(providerResult.manifest, {
      role: sprite.role,
    });
    if (!gauntlet.ok) {
      const path = this.writeAttempt({
        request,
        sprite,
        prompt,
        providerResult,
        gauntlet,
        reason: gauntlet.reason,
      });
      return {
        kind: "rejected",
        rejected: {
          entityId: sprite.entityId,
          fallbackSpriteId: sprite.fallbackSpriteId,
          reason: gauntlet.reason,
          sourceArtifactPath: path,
        },
      };
    }

    const entry = this.atlas.getOrSet(atlasKey, gauntlet.manifest);
    const path = this.writeAttempt({
      request,
      sprite,
      prompt,
      providerResult,
      gauntlet,
      reason: null,
    });
    this.sourcePaths.set(entry.keyString, path);

    return {
      kind: "accepted",
      accepted: {
        entityId: sprite.entityId,
        atlasKey,
        manifest: entry.manifest,
        sourceArtifactPath: path,
      },
    };
  }

  private writeAttempt({
    request,
    sprite,
    prompt,
    providerResult,
    gauntlet,
    reason,
  }: {
    readonly request: ArtDirectorBatchRequest;
    readonly sprite: ArtDirectorSpriteRequest;
    readonly prompt: string;
    readonly providerResult: ArtDirectorProviderResult;
    readonly gauntlet: ReturnType<typeof runArtGauntlet> | null;
    readonly reason: string | null;
  }): string {
    const atlasKey = spriteAtlasKey(
      request.themeId,
      sprite.entityId,
      request.seed,
    );
    return writeArtDirectorAttemptArtifact(
      {
        themeId: request.themeId,
        entityId: sprite.entityId,
        seed: request.seed,
        prompt,
        providerResult,
        gauntlet,
        atlasKey,
        fallbackSpriteId: sprite.fallbackSpriteId,
        outcome:
          reason === null
            ? {
                kind: "accepted",
                atlasKey: serializeSpriteAtlasKey(atlasKey),
              }
            : {
                kind: "rejected",
                fallbackSpriteId: sprite.fallbackSpriteId,
                reason,
              },
        createdAt: this.now(),
      },
      {
        ...this.artifacts,
        runId: this.artifacts?.runId ?? `art-${request.seed}`,
      },
    );
  }
}

