118	const runProcess = ({
119	  command,
120	  args,
121	  timeoutMs,
122	  exec,
123	  now,
124	}: {
125	  readonly command: string;
126	  readonly args: readonly string[];
127	  readonly timeoutMs: number;
128	  readonly exec: ArtProviderExec;
129	  readonly now: () => number;
130	}): Promise<ProcessRunResult> =>
131	  new Promise((resolve) => {
132	    const startedAt = now();
133	    const stdoutChunks: string[] = [];
134	    const stderrChunks: string[] = [];
135	    let settled = false;
136	    let child: ArtProviderProcess;
137	
138	    const usage = (): ArtDirectorProviderUsage => ({
139	      latencyMs: Math.max(0, now() - startedAt),
140	      tokens: null,
141	    });
142	
143	    const finish = (result: ProcessRunResult): void => {
144	      if (settled) {
145	        return;
146	      }
147	
148	      settled = true;
149	      clearTimeout(timeout);
150	      resolve(result);
151	    };
152	
153	    const timeout = setTimeout(() => {
154	      const stdout = stdoutChunks.join("");
155	      const stderr = stderrChunks.join("");
156	      const killed = child.kill("SIGTERM");
157	      finish({
158	        ok: false,
159	        code: "timeout",
160	        message: `process timed out after ${timeoutMs}ms; killed=${killed}`,
161	        stdout,
162	        stderr,
163	        usage: usage(),
164	      });
165	    }, timeoutMs);
166	
167	    try {
168	      child = exec(command, args, { stdin: "ignore" });
169	    } catch (error) {
170	      finish({
171	        ok: false,
172	        code: "process_error",
173	        message: error instanceof Error ? error.message : String(error),
174	        stdout: "",
175	        stderr: "",
176	        usage: usage(),
177	      });
178	      return;
179	    }
