 28	export type AmbientArtDirectorOptions = {
 29	  readonly provider?: ArtDirectorSpriteProvider;
 30	  readonly atlas?: SpriteAtlasCache;
 31	  readonly mode?: ArtDirectorMode;
 32	  readonly timeoutMs?: number;
