 37	export class AmbientArtDirector implements ArtDirector {
 38	  private readonly provider: ArtDirectorSpriteProvider;
 39	  private readonly atlas: SpriteAtlasCache;
 40	  private readonly mode: ArtDirectorMode;
 41	  private readonly timeoutMs: number | undefined;
 42	  private readonly artifacts: ArtDirectorArtifactOptions | undefined;
 43	  private readonly now: () => string;
 44	  private readonly sourcePaths = new Map<string, string>();
 45	
 46	  constructor(options: AmbientArtDirectorOptions = {}) {
 47	    this.provider = options.provider ?? new AmbientArtDirectorProvider();
 48	    this.atlas = options.atlas ?? new SpriteAtlasCache();
 49	    this.mode = options.mode ?? artDirectorModeFromEnv();
 50	    this.timeoutMs = options.timeoutMs;
 51	    this.artifacts = options.artifacts;
 52	    this.now = options.now ?? (() => new Date().toISOString());
 53	  }
 54	
 55	  async generateSprites(
 56	    request: ArtDirectorBatchRequest,
 57	  ): Promise<ArtDirectorBatchResult> {
 58	    const accepted: ArtDirectorAcceptedSprite[] = [];
 59	    const rejected: ArtDirectorRejectedSprite[] = [];
 60	
 61	    for (const sprite of request.sprites) {
 62	      const atlasKey = spriteAtlasKey(
 63	        request.themeId,
 64	        sprite.entityId,
 65	        request.seed,
 66	      );
 67	      const atlasKeyString = serializeSpriteAtlasKey(atlasKey);
 68	      const cached = this.atlas.get(atlasKey);
 69	      if (cached !== null) {
 70	        accepted.push({
 71	          entityId: sprite.entityId,
 72	          atlasKey,
 73	          manifest: cached.manifest,
 74	          sourceArtifactPath:
 75	            this.sourcePaths.get(atlasKeyString) ?? "atlas-cache",
 76	        });
 77	        continue;
 78	      }
 79	
 80	      if (this.mode === "fallback") {
 81	        rejected.push({
 82	          entityId: sprite.entityId,
 83	          fallbackSpriteId: sprite.fallbackSpriteId,
 84	          reason: "ART=fallback",
 85	          sourceArtifactPath: null,
 86	        });
 87	        continue;
 88	      }
 89	
 90	      const prompt = buildArtDirectorPrompt({
 91	        themeId: request.themeId,
 92	        entityId: sprite.entityId,
 93	        entityPrompt: sprite.prompt,
 94	        role: sprite.role,
 95	        size: sprite.size,
 96	        paletteHint: sprite.paletteHint,
 97	      });
 98	      const providerResult = await this.provider.generateSprite(prompt, {
 99	        ...(this.timeoutMs === undefined ? {} : { timeoutMs: this.timeoutMs }),
100	      });
101	      const result = this.applyProviderResult({
102	        request,
103	        sprite,
104	        prompt,
105	        providerResult,
106	      });
107	
108	      if (result.kind === "accepted") {
109	        accepted.push(result.accepted);
110	      } else {
111	        rejected.push(result.rejected);
112	      }
113	    }
114	
115	    return { accepted, rejected };
116	  }
117	
118	  private applyProviderResult({
119	    request,
120	    sprite,
121	    prompt,
122	    providerResult,
123	  }: {
124	    readonly request: ArtDirectorBatchRequest;
125	    readonly sprite: ArtDirectorSpriteRequest;
126	    readonly prompt: string;
127	    readonly providerResult: ArtDirectorProviderResult;
128	  }):
129	    | { readonly kind: "accepted"; readonly accepted: ArtDirectorAcceptedSprite }
130	    | { readonly kind: "rejected"; readonly rejected: ArtDirectorRejectedSprite } {
131	    const atlasKey = spriteAtlasKey(
132	      request.themeId,
133	      sprite.entityId,
134	      request.seed,
135	    );
136	
137	    if (!providerResult.ok) {
138	      const path = this.writeAttempt({
139	        request,
140	        sprite,
141	        prompt,
142	        providerResult,
143	        gauntlet: null,
144	        reason: providerResult.error.message,
145	      });
146	      return {
147	        kind: "rejected",
148	        rejected: {
149	          entityId: sprite.entityId,
150	          fallbackSpriteId: sprite.fallbackSpriteId,
151	          reason: providerResult.error.message,
152	          sourceArtifactPath: path,
153	        },
154	      };
155	    }
156	
157	    const gauntlet = runArtGauntlet(providerResult.manifest, {
158	      role: sprite.role,
159	    });
160	    if (!gauntlet.ok) {
161	      const path = this.writeAttempt({
162	        request,
163	        sprite,
164	        prompt,
165	        providerResult,
166	        gauntlet,
167	        reason: gauntlet.reason,
168	      });
169	      return {
170	        kind: "rejected",
171	        rejected: {
172	          entityId: sprite.entityId,
173	          fallbackSpriteId: sprite.fallbackSpriteId,
174	          reason: gauntlet.reason,
175	          sourceArtifactPath: path,
176	        },
177	      };
178	    }
179	
180	    const entry = this.atlas.getOrSet(atlasKey, gauntlet.manifest);
181	    const path = this.writeAttempt({
182	      request,
183	      sprite,
184	      prompt,
185	      providerResult,
186	      gauntlet,
187	      reason: null,
188	    });
189	    this.sourcePaths.set(entry.keyString, path);
190	
191	    return {
192	      kind: "accepted",
193	      accepted: {
194	        entityId: sprite.entityId,
195	        atlasKey,
196	        manifest: entry.manifest,
197	        sourceArtifactPath: path,
198	      },
199	    };
200	  }
201	
202	  private writeAttempt({
203	    request,
204	    sprite,
205	    prompt,
206	    providerResult,
207	    gauntlet,
208	    reason,
209	  }: {
210	    readonly request: ArtDirectorBatchRequest;
211	    readonly sprite: ArtDirectorSpriteRequest;
212	    readonly prompt: string;
213	    readonly providerResult: ArtDirectorProviderResult;
214	    readonly gauntlet: ReturnType<typeof runArtGauntlet> | null;
215	    readonly reason: string | null;
216	  }): string {
217	    const atlasKey = spriteAtlasKey(
218	      request.themeId,
219	      sprite.entityId,
220	      request.seed,
221	    );
222	    return writeArtDirectorAttemptArtifact(
223	      {
224	        themeId: request.themeId,
225	        entityId: sprite.entityId,
226	        seed: request.seed,
227	        prompt,
228	        providerResult,
229	        gauntlet,
230	        atlasKey,
231	        fallbackSpriteId: sprite.fallbackSpriteId,
232	        outcome:
233	          reason === null
234	            ? {
235	                kind: "accepted",
236	                atlasKey: serializeSpriteAtlasKey(atlasKey),
237	              }
238	            : {
239	                kind: "rejected",
240	                fallbackSpriteId: sprite.fallbackSpriteId,
241	                reason,
242	              },
243	        createdAt: this.now(),
244	      },
245	      {
246	        ...this.artifacts,
247	        runId: this.artifacts?.runId ?? `art-${request.seed}`,
248	      },
249	    );
250	  }
251	}
