  2	  MAX_PALETTE_COLORS,
  3	  MIN_FILLED_RATIO,
  4	  formatSpriteValidationErrors,
  5	  rasterizeSpriteManifest,
  6	  spriteManifestStats,
  7	  validateSpriteManifest,
