 10	import type {
 11	  ArtGauntletReport,
 12	  ArtGauntletStage,
 13	  ArtGauntletStageReport,
 14	} from "./types.js";
 15	
 16	const NORMAL_PALETTE_MAX = 6;
 17	const SIGNATURE_PALETTE_MAX = 8;
 18	
 19	export type RunArtGauntletOptions = {
 20	  readonly role?: string;
 21	  readonly scale?: number;
 22	};
 23	
 24	export const runArtGauntlet = (
 25	  candidate: unknown,
 26	  options: RunArtGauntletOptions = {},
 27	): ArtGauntletReport => {
 28	  const stages: ArtGauntletStageReport[] = [];
 29	  const validated = validateSpriteManifest(candidate);
 30	
 31	  if (!validated.ok) {
 32	    return reject("schema", formatSpriteValidationErrors(validated.errors), [
 33	      ...stages,
 34	      {
 35	        stage: "schema",
 36	        ok: false,
 37	        details: validated.errors.map(
 38	          (error) => `${error.path}: ${error.message}`,
 39	        ),
 40	      },
 41	    ]);
 42	  }
 43	
 44	  const manifest = validated.manifest;
 45	  stages.push({ stage: "schema", ok: true, details: [] });
 46	
 47	  const palette = checkPaletteBudget(manifest, options.role);
 48	  stages.push(palette);
 49	  if (!palette.ok) {
 50	    return reject("palette", palette.details.join("; "), stages);
 51	  }
 52	
 53	  try {
 54	    rasterizeSpriteManifest(manifest, { scale: options.scale ?? 1 });
 55	    stages.push({ stage: "render", ok: true, details: [] });
 56	  } catch (error) {
 57	    const message = error instanceof Error ? error.message : String(error);
 58	    stages.push({ stage: "render", ok: false, details: [message] });
 59	    return reject("render", message, stages);
 60	  }
 61	
 62	  const readability = checkReadability(manifest);
 63	  stages.push(readability);
 64	  if (!readability.ok) {
 65	    return reject("readability", readability.details.join("; "), stages);
 66	  }
 67	
 68	  return { ok: true, manifest, stages };
 69	};
 70	
 71	const checkPaletteBudget = (
 72	  manifest: SpriteManifest,
 73	  role: string | undefined,
 74	): ArtGauntletStageReport => {
 75	  const max =
 76	    role === "signature" || role === "boss"
 77	      ? SIGNATURE_PALETTE_MAX
 78	      : NORMAL_PALETTE_MAX;
 79	
 80	  if (manifest.palette.length > MAX_PALETTE_COLORS) {
 81	    return {
 82	      stage: "palette",
 83	      ok: false,
 84	      details: [`palette exceeds hard max ${MAX_PALETTE_COLORS}`],
 85	    };
 86	  }
 87	
 88	  if (manifest.palette.length > max) {
 89	    return {
 90	      stage: "palette",
 91	      ok: false,
 92	      details: [
 93	        `palette has ${manifest.palette.length} colors; ${role ?? "normal"} max is ${max}`,
 94	      ],
 95	    };
 96	  }
 97	
 98	  return { stage: "palette", ok: true, details: [] };
 99	};
100	
101	const checkReadability = (
102	  manifest: SpriteManifest,
103	): ArtGauntletStageReport => {
104	  const stats = spriteManifestStats(manifest);
105	  const details: string[] = [];
106	
107	  if (stats.filledRatio < MIN_FILLED_RATIO) {
108	    details.push(
109	      `filled ratio ${stats.filledRatio.toFixed(3)} below ${MIN_FILLED_RATIO}`,
110	    );
111	  }
112	
113	  if (stats.occupiedRows < 3) {
114	    details.push(`occupied rows ${stats.occupiedRows} below 3`);
115	  }
116	
117	  if (stats.occupiedColumns < 3) {
118	    details.push(`occupied columns ${stats.occupiedColumns} below 3`);
119	  }
120	
121	  if (stats.visibleColorCount < 2) {
122	    details.push(`visible colors ${stats.visibleColorCount} below 2`);
123	  }
124	
125	  return {
126	    stage: "readability",
127	    ok: details.length === 0,
128	    details,
129	  };
130	};
131	
132	const reject = (
133	  rejectedAt: ArtGauntletStage,
134	  reason: string,
135	  stages: readonly ArtGauntletStageReport[],
136	): ArtGauntletReport => ({
137	  ok: false,
138	  rejectedAt,
139	  reason,
140	  stages,
141	});

